import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const userSchema = z.object({
  name: z.string(),
  email: z.string(),
  password: z.string(),
  role: z.string(),
  isActive: z.string(),
});

type UserFormData = z.infer<typeof userSchema>;

interface UserFormProps {
  onSubmit: (data: UserFormData) => Promise<void>;
  initialData?: Partial<UserFormData>;
}

export default function UserForm({ onSubmit, initialData }: UserFormProps) {
  const [isLoading, setIsLoading] = useState(false);
  const { register, handleSubmit, formState: { errors } } = useForm<UserFormData>({
    resolver: zodResolver(userSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: UserFormData) => {
    setIsLoading(true);
    try {
      await onSubmit(data);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-4">
      <div>
        <label className="block text-sm font-medium mb-1">Name</label>
        <input {...register("name")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.name && <p className="text-red-500 text-sm">{errors.name.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Email</label>
        <input {...register("email")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.email && <p className="text-red-500 text-sm">{errors.email.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Password</label>
        <input {...register("password")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.password && <p className="text-red-500 text-sm">{errors.password.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Role</label>
        <input {...register("role")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.role && <p className="text-red-500 text-sm">{errors.role.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Isactive</label>
        <input {...register("isActive")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.isActive && <p className="text-red-500 text-sm">{errors.isActive.message}</p>}
      </div>
      <button type="submit" disabled={isLoading} className="w-full py-2 bg-blue-600 text-white rounded-lg">
        {isLoading ? 'Saving...' : 'Save User'}
      </button>
    </form>
  );
}
