<script lang="ts">
  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<User> = {};

  interface User {
    name: string;
    email: string;
    password: string;
    role: string;
    isActive: string;
  }

  const schema = z.object({
    name: z.string().min(1),
    email: z.string().min(1),
    password: z.string().min(1),
    role: z.string().min(1),
    isActive: z.string().min(1),
  });

  let formData: Partial<User> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: User }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as User);
    } finally {
      isLoading = false;
    }
  }
</script>

