// user.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const userSchema = z.object({
  name: z.string(),
  email: z.string(),
  password: z.string(),
  role: z.string(),
  isActive: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [users, total] = await Promise.all([
    prisma.user.findMany({ where, skip, take: Number(limit) }),
    prisma.user.count({ where }),
  ]);

  res.json({ items: users, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const user = await prisma.user.findUnique({
    where: { id: req.params.id },
  });

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  res.json(user);
});

// Create
router.post('/', validateRequest(userSchema), async (req, res) => {
  const user = await prisma.user.create({
    data: req.body,
  });

  res.status(201).json(user);
});

// Update
router.put('/:id', validateRequest(userSchema.partial()), async (req, res) => {
  const user = await prisma.user.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(user);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.user.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
