  @Input() initialData?: Partial<Product>;
  @Output() formSubmit = new EventEmitter<Product>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      name: [this.initialData?.name || '', Validators.required],
      price: [this.initialData?.price || '', Validators.required],
      description: [this.initialData?.description || '', Validators.required],
      stock: [this.initialData?.stock || '', Validators.required],
      category: [this.initialData?.category || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
