// product.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const productSchema = z.object({
  name: z.string(),
  price: z.string(),
  description: z.string(),
  stock: z.string(),
  category: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [products, total] = await Promise.all([
    prisma.product.findMany({ where, skip, take: Number(limit) }),
    prisma.product.count({ where }),
  ]);

  res.json({ items: products, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const product = await prisma.product.findUnique({
    where: { id: req.params.id },
  });

  if (!product) {
    return res.status(404).json({ error: 'Product not found' });
  }

  res.json(product);
});

// Create
router.post('/', validateRequest(productSchema), async (req, res) => {
  const product = await prisma.product.create({
    data: req.body,
  });

  res.status(201).json(product);
});

// Update
router.put('/:id', validateRequest(productSchema.partial()), async (req, res) => {
  const product = await prisma.product.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(product);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.product.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
