import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

interface Order {
  orderNumber: string;
  total: string;
  status: string;
  items: string;
}

@Component({
  selector: 'app-order-form',
  templateUrl: './order-form.component.html',
})
export class OrderFormComponent implements OnInit {
  @Input() initialData?: Partial<Order>;
  @Output() formSubmit = new EventEmitter<Order>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      orderNumber: [this.initialData?.orderNumber || '', Validators.required],
      total: [this.initialData?.total || '', Validators.required],
      status: [this.initialData?.status || '', Validators.required],
      items: [this.initialData?.items || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
