<script lang="ts">
  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Order> = {};

  interface Order {
    orderNumber: string;
    total: string;
    status: string;
    items: string;
  }

  const schema = z.object({
    orderNumber: z.string().min(1),
    total: z.string().min(1),
    status: z.string().min(1),
    items: z.string().min(1),
  });

  let formData: Partial<Order> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Order }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Order);
    } finally {
      isLoading = false;
    }
  }
</script>

