// order.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const orderSchema = z.object({
  orderNumber: z.string(),
  total: z.string(),
  status: z.string(),
  items: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [orders, total] = await Promise.all([
    prisma.order.findMany({ where, skip, take: Number(limit) }),
    prisma.order.count({ where }),
  ]);

  res.json({ items: orders, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const order = await prisma.order.findUnique({
    where: { id: req.params.id },
  });

  if (!order) {
    return res.status(404).json({ error: 'Order not found' });
  }

  res.json(order);
});

// Create
router.post('/', validateRequest(orderSchema), async (req, res) => {
  const order = await prisma.order.create({
    data: req.body,
  });

  res.status(201).json(order);
});

// Update
router.put('/:id', validateRequest(orderSchema.partial()), async (req, res) => {
  const order = await prisma.order.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(order);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.order.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
