// lib/screens/order_form_screen.dart
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../providers/order_provider.dart';
import '../models/order.dart';

class OrderFormScreen extends StatefulWidget {
  final Order? order;

  const OrderFormScreen({Key? key, this.order}) : super(key: key);

  @override
  State<OrderFormScreen> createState() => _OrderFormScreenState();
}

class _OrderFormScreenState extends State<OrderFormScreen> {
  final _formKey = GlobalKey<FormState>();
  bool _isLoading = false;

  late TextEditingController _orderNumberController;
  late TextEditingController _totalController;
  late TextEditingController _statusController;
  late TextEditingController _itemsController;

  @override
  void initState() {
    super.initState();
    _orderNumberController = TextEditingController(text: widget.order?.orderNumber ?? '');
    _totalController = TextEditingController(text: widget.order?.total ?? '');
    _statusController = TextEditingController(text: widget.order?.status ?? '');
    _itemsController = TextEditingController(text: widget.order?.items ?? '');
  }

  @override
  void dispose() {
    _orderNumberController.dispose();
    _totalController.dispose();
    _statusController.dispose();
    _itemsController.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isLoading = true);

    try {
      final provider = Provider.of<OrderProvider>(context, listen: false);
      final data = Order(
        orderNumber: _orderNumberController.text,
        total: _totalController.text,
        status: _statusController.text,
        items: _itemsController.text,
      );

      if (widget.order != null) {
        await provider.update(widget.order!.id, data);
      } else {
        await provider.create(data);
      }

      Navigator.pop(context);
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e')),
      );
    } finally {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.order != null ? 'Edit Order' : 'Create Order'),
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(16),
          children: [
