  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Customer> = {};

  interface Customer {
    name: string;
    email: string;
    phone: string;
    address: string;
  }

  const schema = z.object({
    name: z.string().min(1),
    email: z.string().min(1),
    phone: z.string().min(1),
    address: z.string().min(1),
  });

  let formData: Partial<Customer> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Customer }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Customer);
    } finally {
      isLoading = false;
