// customer.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const customerSchema = z.object({
  name: z.string(),
  email: z.string(),
  phone: z.string(),
  address: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [customers, total] = await Promise.all([
    prisma.customer.findMany({ where, skip, take: Number(limit) }),
    prisma.customer.count({ where }),
  ]);

  res.json({ items: customers, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const customer = await prisma.customer.findUnique({
    where: { id: req.params.id },
  });

  if (!customer) {
    return res.status(404).json({ error: 'Customer not found' });
  }

  res.json(customer);
});

// Create
router.post('/', validateRequest(customerSchema), async (req, res) => {
  const customer = await prisma.customer.create({
    data: req.body,
  });

  res.status(201).json(customer);
});

// Update
router.put('/:id', validateRequest(customerSchema.partial()), async (req, res) => {
  const customer = await prisma.customer.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(customer);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.customer.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
