package handlers

import (
    "net/http"
    "github.com/gin-gonic/gin"
    "github.com/google/uuid"
    "your-app/models"
    "your-app/database"
)

func GetCustomers(c *gin.Context) {
    var customers []models.Customer
    database.DB.Find(&customers)
    c.JSON(http.StatusOK, gin.H{"items": customers})
}

func GetCustomer(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    var customer models.Customer
    if err := database.DB.First(&customer, "id = ?", id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Customer not found"})
        return
    }
    c.JSON(http.StatusOK, customer)
}

func CreateCustomer(c *gin.Context) {
    var customer models.Customer
    if err := c.ShouldBindJSON(&customer); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    database.DB.Create(&customer)
    c.JSON(http.StatusCreated, customer)
}

func UpdateCustomer(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    var customer models.Customer
    if err := database.DB.First(&customer, "id = ?", id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Customer not found"})
        return
    }
    if err := c.ShouldBindJSON(&customer); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    database.DB.Save(&customer)
    c.JSON(http.StatusOK, customer)
}

func DeleteCustomer(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    database.DB.Delete(&models.Customer{}, "id = ?", id)
    c.Status(http.StatusNoContent)
}


// routes.go
func SetupRoutes(r *gin.Engine) {
    api := r.Group("/api")
    {
        api.GET("/customers", handlers.GetCustomers)
        api.GET("/customers/:id", handlers.GetCustomer)
        api.POST("/customers", handlers.CreateCustomer)
        api.PUT("/customers/:id", handlers.UpdateCustomer)
        api.DELETE("/customers/:id", handlers.DeleteCustomer)
    }
}
