import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

interface Invoice {
  invoiceNumber: string;
  amount: string;
  dueDate: string;
  status: string;
}

@Component({
  selector: 'app-invoice-form',
  templateUrl: './invoice-form.component.html',
})
export class InvoiceFormComponent implements OnInit {
  @Input() initialData?: Partial<Invoice>;
  @Output() formSubmit = new EventEmitter<Invoice>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      invoiceNumber: [this.initialData?.invoiceNumber || '', Validators.required],
      amount: [this.initialData?.amount || '', Validators.required],
      dueDate: [this.initialData?.dueDate || '', Validators.required],
      status: [this.initialData?.status || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
