<script lang="ts">
  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Invoice> = {};

  interface Invoice {
    invoiceNumber: string;
    amount: string;
    dueDate: string;
    status: string;
  }

  const schema = z.object({
    invoiceNumber: z.string().min(1),
    amount: z.string().min(1),
    dueDate: z.string().min(1),
    status: z.string().min(1),
  });

  let formData: Partial<Invoice> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Invoice }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Invoice);
    } finally {
      isLoading = false;
    }
  }
</script>

