// invoice.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const invoiceSchema = z.object({
  invoiceNumber: z.string(),
  amount: z.string(),
  dueDate: z.string(),
  status: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [invoices, total] = await Promise.all([
    prisma.invoice.findMany({ where, skip, take: Number(limit) }),
    prisma.invoice.count({ where }),
  ]);

  res.json({ items: invoices, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const invoice = await prisma.invoice.findUnique({
    where: { id: req.params.id },
  });

  if (!invoice) {
    return res.status(404).json({ error: 'Invoice not found' });
  }

  res.json(invoice);
});

// Create
router.post('/', validateRequest(invoiceSchema), async (req, res) => {
  const invoice = await prisma.invoice.create({
    data: req.body,
  });

  res.status(201).json(invoice);
});

// Update
router.put('/:id', validateRequest(invoiceSchema.partial()), async (req, res) => {
  const invoice = await prisma.invoice.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(invoice);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.invoice.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
