package com.example.app.service;

import com.example.app.dto.*;
import com.example.app.entity.Invoice;
import com.example.app.repository.InvoiceRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.*;
import org.springframework.stereotype.Service;
import jakarta.persistence.EntityNotFoundException;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class InvoiceService {
    private final InvoiceRepository repository;

    public Page<InvoiceResponse> findAll(Pageable pageable) {
        return repository.findAll(pageable).map(this::toResponse);
    }

    public InvoiceResponse findById(UUID id) {
        return toResponse(repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Invoice not found")));
    }

    public InvoiceResponse create(InvoiceRequest request) {
        Invoice entity = Invoice.builder()
            .invoiceNumber(request.getInvoiceNumber())
            .amount(request.getAmount())
            .dueDate(request.getDueDate())
            .status(request.getStatus())
            .build();
        return toResponse(repository.save(entity));
    }

    public InvoiceResponse update(UUID id, InvoiceRequest request) {
        Invoice entity = repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Invoice not found"));
        entity.setInvoiceNumber(request.getInvoiceNumber());
        entity.setAmount(request.getAmount());
        entity.setDueDate(request.getDueDate());
        entity.setStatus(request.getStatus());
        return toResponse(repository.save(entity));
    }

    public void delete(UUID id) {
        repository.deleteById(id);
    }

    private InvoiceResponse toResponse(Invoice entity) {
        return InvoiceResponse.builder()
            .id(entity.getId())
            .invoiceNumber(entity.getInvoiceNumber())
            .amount(entity.getAmount())
            .dueDate(entity.getDueDate())
            .status(entity.getStatus())
            .build();
    }
}
