// lib/screens/invoice_form_screen.dart
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../providers/invoice_provider.dart';
import '../models/invoice.dart';

class InvoiceFormScreen extends StatefulWidget {
  final Invoice? invoice;

  const InvoiceFormScreen({Key? key, this.invoice}) : super(key: key);

  @override
  State<InvoiceFormScreen> createState() => _InvoiceFormScreenState();
}

class _InvoiceFormScreenState extends State<InvoiceFormScreen> {
  final _formKey = GlobalKey<FormState>();
  bool _isLoading = false;

  late TextEditingController _invoiceNumberController;
  late TextEditingController _amountController;
  late TextEditingController _dueDateController;
  late TextEditingController _statusController;

  @override
  void initState() {
    super.initState();
    _invoiceNumberController = TextEditingController(text: widget.invoice?.invoiceNumber ?? '');
    _amountController = TextEditingController(text: widget.invoice?.amount ?? '');
    _dueDateController = TextEditingController(text: widget.invoice?.dueDate ?? '');
    _statusController = TextEditingController(text: widget.invoice?.status ?? '');
  }

  @override
  void dispose() {
    _invoiceNumberController.dispose();
    _amountController.dispose();
    _dueDateController.dispose();
    _statusController.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isLoading = true);

    try {
      final provider = Provider.of<InvoiceProvider>(context, listen: false);
      final data = Invoice(
        invoiceNumber: _invoiceNumberController.text,
        amount: _amountController.text,
        dueDate: _dueDateController.text,
        status: _statusController.text,
      );

      if (widget.invoice != null) {
        await provider.update(widget.invoice!.id, data);
      } else {
        await provider.create(data);
      }

      Navigator.pop(context);
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e')),
      );
    } finally {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.invoice != null ? 'Edit Invoice' : 'Create Invoice'),
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(16),
          children: [
            TextFormField(
              controller: _invoiceNumberController,
              decoration: const InputDecoration(labelText: 'Invoicenumber'),
              validator: (v) => v?.isEmpty ?? true ? 'Invoicenumber is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _amountController,
              decoration: const InputDecoration(labelText: 'Amount'),
              validator: (v) => v?.isEmpty ?? true ? 'Amount is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _dueDateController,
              decoration: const InputDecoration(labelText: 'Duedate'),
              validator: (v) => v?.isEmpty ?? true ? 'Duedate is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _statusController,
              decoration: const InputDecoration(labelText: 'Status'),
              validator: (v) => v?.isEmpty ?? true ? 'Status is required' : null,
            ),
            const SizedBox(height: 16),
            ElevatedButton(
              onPressed: _isLoading ? null : _submit,
              child: _isLoading
                  ? const CircularProgressIndicator()
                  : Text(widget.invoice != null ? 'Update' : 'Create'),
            ),
          ],
        ),
      ),
    );
  }
}
