import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

interface Employee {
  name: string;
  email: string;
  department: string;
  salary: string;
  joiningDate: string;
}

@Component({
  selector: 'app-employee-form',
  templateUrl: './employee-form.component.html',
})
export class EmployeeFormComponent implements OnInit {
  @Input() initialData?: Partial<Employee>;
  @Output() formSubmit = new EventEmitter<Employee>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      name: [this.initialData?.name || '', Validators.required],
      email: [this.initialData?.email || '', Validators.required],
      department: [this.initialData?.department || '', Validators.required],
      salary: [this.initialData?.salary || '', Validators.required],
      joiningDate: [this.initialData?.joiningDate || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
