<script lang="ts">
  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Employee> = {};

  interface Employee {
    name: string;
    email: string;
    department: string;
    salary: string;
    joiningDate: string;
  }

  const schema = z.object({
    name: z.string().min(1),
    email: z.string().min(1),
    department: z.string().min(1),
    salary: z.string().min(1),
    joiningDate: z.string().min(1),
  });

  let formData: Partial<Employee> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Employee }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Employee);
    } finally {
      isLoading = false;
    }
  }
</script>

