// employee.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const employeeSchema = z.object({
  name: z.string(),
  email: z.string(),
  department: z.string(),
  salary: z.string(),
  joiningDate: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [employees, total] = await Promise.all([
    prisma.employee.findMany({ where, skip, take: Number(limit) }),
    prisma.employee.count({ where }),
  ]);

  res.json({ items: employees, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const employee = await prisma.employee.findUnique({
    where: { id: req.params.id },
  });

  if (!employee) {
    return res.status(404).json({ error: 'Employee not found' });
  }

  res.json(employee);
});

// Create
router.post('/', validateRequest(employeeSchema), async (req, res) => {
  const employee = await prisma.employee.create({
    data: req.body,
  });

  res.status(201).json(employee);
});

// Update
router.put('/:id', validateRequest(employeeSchema.partial()), async (req, res) => {
  const employee = await prisma.employee.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(employee);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.employee.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
