import com.example.app.repository.EmployeeRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.*;
import org.springframework.stereotype.Service;
import jakarta.persistence.EntityNotFoundException;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class EmployeeService {
    private final EmployeeRepository repository;

    public Page<EmployeeResponse> findAll(Pageable pageable) {
        return repository.findAll(pageable).map(this::toResponse);
    }

    public EmployeeResponse findById(UUID id) {
        return toResponse(repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Employee not found")));
    }

    public EmployeeResponse create(EmployeeRequest request) {
        Employee entity = Employee.builder()
            .name(request.getName())
            .email(request.getEmail())
            .department(request.getDepartment())
            .salary(request.getSalary())
            .joiningDate(request.getJoiningDate())
            .build();
        return toResponse(repository.save(entity));
    }

    public EmployeeResponse update(UUID id, EmployeeRequest request) {
        Employee entity = repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Employee not found"));
        entity.setName(request.getName());
        entity.setEmail(request.getEmail());
        entity.setDepartment(request.getDepartment());
        entity.setSalary(request.getSalary());
        entity.setJoiningDate(request.getJoiningDate());
        return toResponse(repository.save(entity));
    }

    public void delete(UUID id) {
        repository.deleteById(id);
    }

    private EmployeeResponse toResponse(Employee entity) {
        return EmployeeResponse.builder()
            .id(entity.getId())
            .name(entity.getName())
            .email(entity.getEmail())
            .department(entity.getDepartment())
            .salary(entity.getSalary())
            .joiningDate(entity.getJoiningDate())
            .build();
    }
}
