package handlers

import (
    "net/http"
    "github.com/gin-gonic/gin"
    "github.com/google/uuid"
    "your-app/models"
    "your-app/database"
)

func GetEmployees(c *gin.Context) {
    var employees []models.Employee
    database.DB.Find(&employees)
    c.JSON(http.StatusOK, gin.H{"items": employees})
}

func GetEmployee(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    var employee models.Employee
    if err := database.DB.First(&employee, "id = ?", id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Employee not found"})
        return
    }
    c.JSON(http.StatusOK, employee)
}

func CreateEmployee(c *gin.Context) {
    var employee models.Employee
    if err := c.ShouldBindJSON(&employee); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    database.DB.Create(&employee)
    c.JSON(http.StatusCreated, employee)
}

func UpdateEmployee(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    var employee models.Employee
    if err := database.DB.First(&employee, "id = ?", id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Employee not found"})
        return
    }
    if err := c.ShouldBindJSON(&employee); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    database.DB.Save(&employee)
    c.JSON(http.StatusOK, employee)
}

func DeleteEmployee(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    database.DB.Delete(&models.Employee{}, "id = ?", id)
    c.Status(http.StatusNoContent)
}


// routes.go
func SetupRoutes(r *gin.Engine) {
    api := r.Group("/api")
    {
        api.GET("/employees", handlers.GetEmployees)
        api.GET("/employees/:id", handlers.GetEmployee)
        api.POST("/employees", handlers.CreateEmployee)
        api.PUT("/employees/:id", handlers.UpdateEmployee)
        api.DELETE("/employees/:id", handlers.DeleteEmployee)
    }
}
