  bool _isLoading = false;

  late TextEditingController _nameController;
  late TextEditingController _emailController;
  late TextEditingController _departmentController;
  late TextEditingController _salaryController;
  late TextEditingController _joiningDateController;

  @override
  void initState() {
    super.initState();
    _nameController = TextEditingController(text: widget.employee?.name ?? '');
    _emailController = TextEditingController(text: widget.employee?.email ?? '');
    _departmentController = TextEditingController(text: widget.employee?.department ?? '');
    _salaryController = TextEditingController(text: widget.employee?.salary ?? '');
    _joiningDateController = TextEditingController(text: widget.employee?.joiningDate ?? '');
  }

  @override
  void dispose() {
    _nameController.dispose();
    _emailController.dispose();
    _departmentController.dispose();
    _salaryController.dispose();
    _joiningDateController.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isLoading = true);

    try {
      final provider = Provider.of<EmployeeProvider>(context, listen: false);
      final data = Employee(
        name: _nameController.text,
        email: _emailController.text,
        department: _departmentController.text,
        salary: _salaryController.text,
        joiningDate: _joiningDateController.text,
      );

      if (widget.employee != null) {
        await provider.update(widget.employee!.id, data);
      } else {
        await provider.create(data);
      }

      Navigator.pop(context);
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e')),
      );
    } finally {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.employee != null ? 'Edit Employee' : 'Create Employee'),
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(16),
          children: [
            TextFormField(
              controller: _nameController,
              decoration: const InputDecoration(labelText: 'Name'),
              validator: (v) => v?.isEmpty ?? true ? 'Name is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _emailController,
              decoration: const InputDecoration(labelText: 'Email'),
              validator: (v) => v?.isEmpty ?? true ? 'Email is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _departmentController,
              decoration: const InputDecoration(labelText: 'Department'),
              validator: (v) => v?.isEmpty ?? true ? 'Department is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _salaryController,
              decoration: const InputDecoration(labelText: 'Salary'),
              validator: (v) => v?.isEmpty ?? true ? 'Salary is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _joiningDateController,
              decoration: const InputDecoration(labelText: 'Joiningdate'),
              validator: (v) => v?.isEmpty ?? true ? 'Joiningdate is required' : null,
            ),
            const SizedBox(height: 16),
            ElevatedButton(
              onPressed: _isLoading ? null : _submit,
              child: _isLoading
                  ? const CircularProgressIndicator()
                  : Text(widget.employee != null ? 'Update' : 'Create'),
            ),
          ],
        ),
      ),
    );
  }
}
