// project-form.component.ts
import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

interface Project {
  name: string;
  description: string;
  status: string;
  deadline: string;
}

@Component({
  selector: 'app-project-form',
  templateUrl: './project-form.component.html',
})
export class ProjectFormComponent implements OnInit {
  @Input() initialData?: Partial<Project>;
  @Output() formSubmit = new EventEmitter<Project>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      name: [this.initialData?.name || '', Validators.required],
      description: [this.initialData?.description || '', Validators.required],
      status: [this.initialData?.status || '', Validators.required],
      deadline: [this.initialData?.deadline || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
