<script lang="ts">
  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Project> = {};

  interface Project {
    name: string;
    description: string;
    status: string;
    deadline: string;
  }

  const schema = z.object({
    name: z.string().min(1),
    description: z.string().min(1),
    status: z.string().min(1),
    deadline: z.string().min(1),
  });

  let formData: Partial<Project> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Project }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Project);
    } finally {
      isLoading = false;
    }
  }
