// project.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const projectSchema = z.object({
  name: z.string(),
  description: z.string(),
  status: z.string(),
  deadline: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [projects, total] = await Promise.all([
    prisma.project.findMany({ where, skip, take: Number(limit) }),
    prisma.project.count({ where }),
  ]);

  res.json({ items: projects, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const project = await prisma.project.findUnique({
    where: { id: req.params.id },
  });

  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  res.json(project);
});

// Create
router.post('/', validateRequest(projectSchema), async (req, res) => {
  const project = await prisma.project.create({
    data: req.body,
  });

  res.status(201).json(project);
});

// Update
router.put('/:id', validateRequest(projectSchema.partial()), async (req, res) => {
