package com.example.app.service;

import com.example.app.dto.*;
import com.example.app.entity.Project;
import com.example.app.repository.ProjectRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.*;
import org.springframework.stereotype.Service;
import jakarta.persistence.EntityNotFoundException;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class ProjectService {
    private final ProjectRepository repository;

    public Page<ProjectResponse> findAll(Pageable pageable) {
        return repository.findAll(pageable).map(this::toResponse);
    }

    public ProjectResponse findById(UUID id) {
        return toResponse(repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Project not found")));
    }

    public ProjectResponse create(ProjectRequest request) {
        Project entity = Project.builder()
            .name(request.getName())
            .description(request.getDescription())
            .status(request.getStatus())
            .deadline(request.getDeadline())
            .build();
        return toResponse(repository.save(entity));
    }

    public ProjectResponse update(UUID id, ProjectRequest request) {
        Project entity = repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Project not found"));
        entity.setName(request.getName());
        entity.setDescription(request.getDescription());
        entity.setStatus(request.getStatus());
        entity.setDeadline(request.getDeadline());
        return toResponse(repository.save(entity));
    }

    public void delete(UUID id) {
        repository.deleteById(id);
    }

    private ProjectResponse toResponse(Project entity) {
        return ProjectResponse.builder()
            .id(entity.getId())
            .name(entity.getName())
            .description(entity.getDescription())
            .status(entity.getStatus())
            .deadline(entity.getDeadline())
            .build();
    }
}
