// task.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const taskSchema = z.object({
  title: z.string(),
  description: z.string(),
  priority: z.string(),
  status: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [tasks, total] = await Promise.all([
    prisma.task.findMany({ where, skip, take: Number(limit) }),
    prisma.task.count({ where }),
  ]);

  res.json({ items: tasks, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const task = await prisma.task.findUnique({
    where: { id: req.params.id },
  });

  if (!task) {
    return res.status(404).json({ error: 'Task not found' });
  }

  res.json(task);
});

// Create
router.post('/', validateRequest(taskSchema), async (req, res) => {
  const task = await prisma.task.create({
    data: req.body,
  });

  res.status(201).json(task);
});

// Update
router.put('/:id', validateRequest(taskSchema.partial()), async (req, res) => {
  const task = await prisma.task.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(task);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.task.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
