import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

interface Booking {
  date: string;
  time: string;
  status: string;
  notes: string;
}

@Component({
  selector: 'app-booking-form',
  templateUrl: './booking-form.component.html',
})
export class BookingFormComponent implements OnInit {
  @Input() initialData?: Partial<Booking>;
  @Output() formSubmit = new EventEmitter<Booking>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      date: [this.initialData?.date || '', Validators.required],
      time: [this.initialData?.time || '', Validators.required],
      status: [this.initialData?.status || '', Validators.required],
      notes: [this.initialData?.notes || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
