<script lang="ts">
  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Booking> = {};

  interface Booking {
    date: string;
    time: string;
    status: string;
    notes: string;
  }

  const schema = z.object({
    date: z.string().min(1),
    time: z.string().min(1),
    status: z.string().min(1),
    notes: z.string().min(1),
  });

  let formData: Partial<Booking> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Booking }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Booking);
    } finally {
      isLoading = false;
    }
  }
</script>

