import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const bookingSchema = z.object({
  date: z.string(),
  time: z.string(),
  status: z.string(),
  notes: z.string(),
});

type BookingFormData = z.infer<typeof bookingSchema>;

interface BookingFormProps {
  onSubmit: (data: BookingFormData) => Promise<void>;
  initialData?: Partial<BookingFormData>;
}

export default function BookingForm({ onSubmit, initialData }: BookingFormProps) {
  const [isLoading, setIsLoading] = useState(false);
  const { register, handleSubmit, formState: { errors } } = useForm<BookingFormData>({
    resolver: zodResolver(bookingSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: BookingFormData) => {
    setIsLoading(true);
    try {
      await onSubmit(data);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-4">
      <div>
        <label className="block text-sm font-medium mb-1">Date</label>
        <input {...register("date")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.date && <p className="text-red-500 text-sm">{errors.date.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Time</label>
        <input {...register("time")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.time && <p className="text-red-500 text-sm">{errors.time.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Status</label>
        <input {...register("status")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.status && <p className="text-red-500 text-sm">{errors.status.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Notes</label>
        <input {...register("notes")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.notes && <p className="text-red-500 text-sm">{errors.notes.message}</p>}
      </div>
      <button type="submit" disabled={isLoading} className="w-full py-2 bg-blue-600 text-white rounded-lg">
        {isLoading ? 'Saving...' : 'Save Booking'}
      </button>
    </form>
  );
}
