// booking.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const bookingSchema = z.object({
  date: z.string(),
  time: z.string(),
  status: z.string(),
  notes: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [bookings, total] = await Promise.all([
    prisma.booking.findMany({ where, skip, take: Number(limit) }),
    prisma.booking.count({ where }),
  ]);

  res.json({ items: bookings, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const booking = await prisma.booking.findUnique({
    where: { id: req.params.id },
  });

  if (!booking) {
    return res.status(404).json({ error: 'Booking not found' });
  }

  res.json(booking);
});

// Create
router.post('/', validateRequest(bookingSchema), async (req, res) => {
  const booking = await prisma.booking.create({
    data: req.body,
  });

  res.status(201).json(booking);
});

// Update
router.put('/:id', validateRequest(bookingSchema.partial()), async (req, res) => {
  const booking = await prisma.booking.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(booking);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.booking.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
