// BookingService.java
package com.example.app.service;

import com.example.app.dto.*;
import com.example.app.entity.Booking;
import com.example.app.repository.BookingRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.*;
import org.springframework.stereotype.Service;
import jakarta.persistence.EntityNotFoundException;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class BookingService {
    private final BookingRepository repository;

    public Page<BookingResponse> findAll(Pageable pageable) {
        return repository.findAll(pageable).map(this::toResponse);
    }

    public BookingResponse findById(UUID id) {
        return toResponse(repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Booking not found")));
    }

    public BookingResponse create(BookingRequest request) {
        Booking entity = Booking.builder()
            .date(request.getDate())
            .time(request.getTime())
            .status(request.getStatus())
            .notes(request.getNotes())
            .build();
        return toResponse(repository.save(entity));
    }

    public BookingResponse update(UUID id, BookingRequest request) {
        Booking entity = repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Booking not found"));
        entity.setDate(request.getDate());
        entity.setTime(request.getTime());
        entity.setStatus(request.getStatus());
        entity.setNotes(request.getNotes());
        return toResponse(repository.save(entity));
    }

    public void delete(UUID id) {
        repository.deleteById(id);
    }

    private BookingResponse toResponse(Booking entity) {
        return BookingResponse.builder()
            .id(entity.getId())
            .date(entity.getDate())
            .time(entity.getTime())
            .status(entity.getStatus())
            .notes(entity.getNotes())
            .build();
    }
}
