package handlers

import (
    "net/http"
    "github.com/gin-gonic/gin"
    "github.com/google/uuid"
    "your-app/models"
    "your-app/database"
)

func GetBookings(c *gin.Context) {
    var bookings []models.Booking
    database.DB.Find(&bookings)
    c.JSON(http.StatusOK, gin.H{"items": bookings})
}

func GetBooking(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    var booking models.Booking
    if err := database.DB.First(&booking, "id = ?", id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Booking not found"})
        return
    }
    c.JSON(http.StatusOK, booking)
}

func CreateBooking(c *gin.Context) {
    var booking models.Booking
    if err := c.ShouldBindJSON(&booking); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    database.DB.Create(&booking)
    c.JSON(http.StatusCreated, booking)
}

func UpdateBooking(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    var booking models.Booking
    if err := database.DB.First(&booking, "id = ?", id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Booking not found"})
        return
    }
    if err := c.ShouldBindJSON(&booking); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    database.DB.Save(&booking)
    c.JSON(http.StatusOK, booking)
}

func DeleteBooking(c *gin.Context) {
    id, _ := uuid.Parse(c.Param("id"))
    database.DB.Delete(&models.Booking{}, "id = ?", id)
    c.Status(http.StatusNoContent)
}


// routes.go
func SetupRoutes(r *gin.Engine) {
    api := r.Group("/api")
    {
        api.GET("/bookings", handlers.GetBookings)
        api.GET("/bookings/:id", handlers.GetBooking)
        api.POST("/bookings", handlers.CreateBooking)
        api.PUT("/bookings/:id", handlers.UpdateBooking)
        api.DELETE("/bookings/:id", handlers.DeleteBooking)
    }
}
