            <TextInput
              style={styles.input}
              value={value}
              onChangeText={onChange}
              placeholder="Enter time"
            />
          )}
        />
        {errors.time && <Text style={styles.error}>{errors.time.message}</Text>}
      </View>
      <View style={styles.field}>
        <Text style={styles.label}>Status</Text>
        <Controller
          control={control}
          name="status"
          render={({ field: { onChange, value } }) => (
            <TextInput
              style={styles.input}
              value={value}
              onChangeText={onChange}
              placeholder="Enter status"
            />
          )}
        />
        {errors.status && <Text style={styles.error}>{errors.status.message}</Text>}
      </View>
      <View style={styles.field}>
        <Text style={styles.label}>Notes</Text>
        <Controller
          control={control}
          name="notes"
          render={({ field: { onChange, value } }) => (
            <TextInput
              style={styles.input}
              value={value}
              onChangeText={onChange}
              placeholder="Enter notes"
            />
          )}
        />
        {errors.notes && <Text style={styles.error}>{errors.notes.message}</Text>}
      </View>

      <TouchableOpacity
        style={[styles.button, isLoading && styles.buttonDisabled]}
        onPress={handleSubmit(handleFormSubmit)}
        disabled={isLoading}
      >
        {isLoading ? (
          <ActivityIndicator color="#fff" />
        ) : (
          <Text style={styles.buttonText}>Save Booking</Text>
        )}
      </TouchableOpacity>
    </View>
  );
}

