// lib/screens/booking_form_screen.dart
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../providers/booking_provider.dart';
import '../models/booking.dart';

class BookingFormScreen extends StatefulWidget {
  final Booking? booking;

  const BookingFormScreen({Key? key, this.booking}) : super(key: key);

  @override
  State<BookingFormScreen> createState() => _BookingFormScreenState();
}

class _BookingFormScreenState extends State<BookingFormScreen> {
  final _formKey = GlobalKey<FormState>();
  bool _isLoading = false;

  late TextEditingController _dateController;
  late TextEditingController _timeController;
  late TextEditingController _statusController;
  late TextEditingController _notesController;

  @override
  void initState() {
    super.initState();
    _dateController = TextEditingController(text: widget.booking?.date ?? '');
    _timeController = TextEditingController(text: widget.booking?.time ?? '');
    _statusController = TextEditingController(text: widget.booking?.status ?? '');
    _notesController = TextEditingController(text: widget.booking?.notes ?? '');
  }

  @override
  void dispose() {
    _dateController.dispose();
    _timeController.dispose();
    _statusController.dispose();
    _notesController.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isLoading = true);

    try {
      final provider = Provider.of<BookingProvider>(context, listen: false);
      final data = Booking(
        date: _dateController.text,
        time: _timeController.text,
        status: _statusController.text,
        notes: _notesController.text,
      );

      if (widget.booking != null) {
        await provider.update(widget.booking!.id, data);
      } else {
        await provider.create(data);
      }

      Navigator.pop(context);
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e')),
      );
    } finally {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.booking != null ? 'Edit Booking' : 'Create Booking'),
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(16),
          children: [
            TextFormField(
              controller: _dateController,
              decoration: const InputDecoration(labelText: 'Date'),
              validator: (v) => v?.isEmpty ?? true ? 'Date is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _timeController,
              decoration: const InputDecoration(labelText: 'Time'),
              validator: (v) => v?.isEmpty ?? true ? 'Time is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _statusController,
              decoration: const InputDecoration(labelText: 'Status'),
              validator: (v) => v?.isEmpty ?? true ? 'Status is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _notesController,
              decoration: const InputDecoration(labelText: 'Notes'),
              validator: (v) => v?.isEmpty ?? true ? 'Notes is required' : null,
            ),
            const SizedBox(height: 16),
            ElevatedButton(
              onPressed: _isLoading ? null : _submit,
              child: _isLoading
                  ? const CircularProgressIndicator()
                  : Text(widget.booking != null ? 'Update' : 'Create'),
            ),
          ],
        ),
      ),
    );
