import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

interface Appointment {
  scheduledAt: string;
  duration: string;
  status: string;
}

@Component({
  selector: 'app-appointment-form',
  templateUrl: './appointment-form.component.html',
})
export class AppointmentFormComponent implements OnInit {
  @Input() initialData?: Partial<Appointment>;
  @Output() formSubmit = new EventEmitter<Appointment>();

  form!: FormGroup;
  isLoading = false;

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      scheduledAt: [this.initialData?.scheduledAt || '', Validators.required],
      duration: [this.initialData?.duration || '', Validators.required],
      status: [this.initialData?.status || '', Validators.required],
    });
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid) return;

    this.isLoading = true;
    try {
      this.formSubmit.emit(this.form.value);
    } finally {
      this.isLoading = false;
    }
  }
}
