  import { createEventDispatcher } from 'svelte';
  import { z } from 'zod';

  export let initialData: Partial<Appointment> = {};

  interface Appointment {
    scheduledAt: string;
    duration: string;
    status: string;
  }

  const schema = z.object({
    scheduledAt: z.string().min(1),
    duration: z.string().min(1),
    status: z.string().min(1),
  });

  let formData: Partial<Appointment> = { ...initialData };
  let errors: Record<string, string> = {};
  let isLoading = false;

  const dispatch = createEventDispatcher<{ submit: Appointment }>();

  async function handleSubmit() {
    const result = schema.safeParse(formData);
    if (!result.success) {
      errors = result.error.flatten().fieldErrors as Record<string, string>;
      return;
    }

    isLoading = true;
    try {
      dispatch('submit', result.data as Appointment);
    } finally {
      isLoading = false;
    }
  }
