// appointment.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';
import { validateRequest } from '../middleware/validate';

const router = Router();
const prisma = new PrismaClient();

const appointmentSchema = z.object({
  scheduledAt: z.string(),
  duration: z.string(),
  status: z.string(),
});

// List all
router.get('/', async (req, res) => {
  const { page = 1, limit = 20, search } = req.query;
  const skip = (Number(page) - 1) * Number(limit);

  const where = search ? {
    OR: [
      { name: { contains: String(search), mode: 'insensitive' } },
    ],
  } : {};

  const [appointments, total] = await Promise.all([
    prisma.appointment.findMany({ where, skip, take: Number(limit) }),
    prisma.appointment.count({ where }),
  ]);

  res.json({ items: appointments, total, page: Number(page), limit: Number(limit) });
});

// Get by ID
router.get('/:id', async (req, res) => {
  const appointment = await prisma.appointment.findUnique({
    where: { id: req.params.id },
  });

  if (!appointment) {
    return res.status(404).json({ error: 'Appointment not found' });
  }

  res.json(appointment);
});

// Create
router.post('/', validateRequest(appointmentSchema), async (req, res) => {
  const appointment = await prisma.appointment.create({
    data: req.body,
  });

  res.status(201).json(appointment);
});

// Update
router.put('/:id', validateRequest(appointmentSchema.partial()), async (req, res) => {
  const appointment = await prisma.appointment.update({
    where: { id: req.params.id },
    data: req.body,
  });

  res.json(appointment);
});

// Delete
router.delete('/:id', async (req, res) => {
  await prisma.appointment.delete({
    where: { id: req.params.id },
  });

  res.status(204).send();
});

export default router;
