package com.example.app.service;

import com.example.app.dto.*;
import com.example.app.entity.Appointment;
import com.example.app.repository.AppointmentRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.*;
import org.springframework.stereotype.Service;
import jakarta.persistence.EntityNotFoundException;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class AppointmentService {
    private final AppointmentRepository repository;

    public Page<AppointmentResponse> findAll(Pageable pageable) {
        return repository.findAll(pageable).map(this::toResponse);
    }

    public AppointmentResponse findById(UUID id) {
        return toResponse(repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Appointment not found")));
    }

    public AppointmentResponse create(AppointmentRequest request) {
        Appointment entity = Appointment.builder()
            .scheduledAt(request.getScheduledAt())
            .duration(request.getDuration())
            .status(request.getStatus())
            .build();
        return toResponse(repository.save(entity));
    }

    public AppointmentResponse update(UUID id, AppointmentRequest request) {
        Appointment entity = repository.findById(id)
            .orElseThrow(() -> new EntityNotFoundException("Appointment not found"));
        entity.setScheduledAt(request.getScheduledAt());
        entity.setDuration(request.getDuration());
        entity.setStatus(request.getStatus());
        return toResponse(repository.save(entity));
    }

    public void delete(UUID id) {
        repository.deleteById(id);
    }

    private AppointmentResponse toResponse(Appointment entity) {
        return AppointmentResponse.builder()
            .id(entity.getId())
            .scheduledAt(entity.getScheduledAt())
            .duration(entity.getDuration())
            .status(entity.getStatus())
            .build();
    }
}
