import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../providers/appointment_provider.dart';
import '../models/appointment.dart';

class AppointmentFormScreen extends StatefulWidget {
  final Appointment? appointment;

  const AppointmentFormScreen({Key? key, this.appointment}) : super(key: key);

  @override
  State<AppointmentFormScreen> createState() => _AppointmentFormScreenState();
}

class _AppointmentFormScreenState extends State<AppointmentFormScreen> {
  final _formKey = GlobalKey<FormState>();
  bool _isLoading = false;

  late TextEditingController _scheduledAtController;
  late TextEditingController _durationController;
  late TextEditingController _statusController;

  @override
  void initState() {
    super.initState();
    _scheduledAtController = TextEditingController(text: widget.appointment?.scheduledAt ?? '');
    _durationController = TextEditingController(text: widget.appointment?.duration ?? '');
    _statusController = TextEditingController(text: widget.appointment?.status ?? '');
  }

  @override
  void dispose() {
    _scheduledAtController.dispose();
    _durationController.dispose();
    _statusController.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isLoading = true);

    try {
      final provider = Provider.of<AppointmentProvider>(context, listen: false);
      final data = Appointment(
        scheduledAt: _scheduledAtController.text,
        duration: _durationController.text,
        status: _statusController.text,
      );

      if (widget.appointment != null) {
        await provider.update(widget.appointment!.id, data);
      } else {
        await provider.create(data);
      }

      Navigator.pop(context);
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e')),
      );
    } finally {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.appointment != null ? 'Edit Appointment' : 'Create Appointment'),
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(16),
          children: [
            TextFormField(
              controller: _scheduledAtController,
              decoration: const InputDecoration(labelText: 'Scheduledat'),
              validator: (v) => v?.isEmpty ?? true ? 'Scheduledat is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _durationController,
              decoration: const InputDecoration(labelText: 'Duration'),
              validator: (v) => v?.isEmpty ?? true ? 'Duration is required' : null,
            ),
            const SizedBox(height: 16),
            TextFormField(
              controller: _statusController,
              decoration: const InputDecoration(labelText: 'Status'),
              validator: (v) => v?.isEmpty ?? true ? 'Status is required' : null,
            ),
            const SizedBox(height: 16),
            ElevatedButton(
              onPressed: _isLoading ? null : _submit,
              child: _isLoading
                  ? const CircularProgressIndicator()
                  : Text(widget.appointment != null ? 'Update' : 'Create'),
            ),
          ],
        ),
      ),
    );
  }
}
