      <div>
        <label className="block text-sm font-medium mb-1">Amount</label>
        <input {...register("amount")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.amount && <p className="text-red-500 text-sm">{errors.amount.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Duedate</label>
        <input {...register("dueDate")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.dueDate && <p className="text-red-500 text-sm">{errors.dueDate.message}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium mb-1">Status</label>
        <input {...register("status")} className="w-full px-3 py-2 border rounded-lg" />
        {errors.status && <p className="text-red-500 text-sm">{errors.status.message}</p>}
      </div>
      <button type="submit" disabled={isLoading} className="w-full py-2 bg-blue-600 text-white rounded-lg">
        {isLoading ? 'Saving...' : 'Save Invoice'}
      </button>
    </form>
  );
}
